waves.frame_eqs_str:
rotx = rotx+bass;
roty = roty+mid;
rotz = rotz+treb;
//rotx = 0;
//roty =0;
//rotz = 0;

//convert rotation values from degrees to radians
t1= t8*rotx/180;
t2 = t8*roty/180;
t3 = t8*rotz/180;

t4 = 3*sin(time+0.66*t8);
t5 = 10+8*cos(time+0.66*t8);

b = 0.5-0.4*cos(time+0.66*t8);
g = 0.5-0.4*sin(time+0.66*t8);

waves.point_eqs_str:
//Define 3D Shape

//Sphere
x1 = (1+value1)*sin(t8*sample)*sin(16*t8*sample);
y1 = (1+value1)*cos(t8*sample);
z1= (1+value1)*sin(t8*sample)*cos(16*t8*sample);

//modulate values to adjust for rotation on multiple axes, convert to world co-ordinates
y2 = y1*cos(t1)-z1*sin(t1);
z2 = y1*sin(t1)+z1*cos(t1);
x2 = z2*sin(t2)+x1*cos(t2);
z3 = z2*cos(t2)-x1*sin(t2);
x3 = x2*cos(t3)-y2*sin(t3);
y3 = y2*cos(t3)+x2*sin(t3);
//move resulting shape in 3d space
x4 = x3+t4;
y4 = y3;
z4 = z3+t5;
//draw 3d shape in 2d
x=0.5+0.5*(x4/(1+z4*0.5));
y=0.5+0.5*(y4/(1+z4*0.5));

r = g+value1;

dim =1; //Dancer dimensions
xpos=0;//Dancer x position variation
ypos=0;//Dancer y position variation



//Position Stabilization
xpos=xpos+(1-dim)/2;
ypos=ypos+(1-dim)/2;

meanbass = 0.01*(meanbass*99+bass);
meantreb = 0.01*(meantreb*99+treb);
meanmid = 0.01*(meanmid*99+mid);
bassdiff = (bass - meanbass)*15;
trebdiff = (treb - meantreb)*15;
middiff = (mid - meanmid)*15;
ba = min(above(bassdiff,0)*bassdiff*.005,.11);
tr = min(above(trebdiff,0)*trebdiff*.005,.11);
mi = min(above(middiff,0)*middiff*.005,.11);

mi2_prg = mi2_prg+mi;
gam = abs(gam-above(mi2_prg,5));
mi2_prg= if(above(mi2_prg,5),0,mi2_prg);

s = sample *15;
//Gambe
x= if(equal(int(s),1),.4,.4);
y= if(equal(int(s),1),.2+((ba+tr)*.5)*gam,.2+((ba+tr)*.5)*gam);

x= if(equal(int(s),2),.5+sin(ba*100)*.03,x);
y= if(equal(int(s),2),.4,y);

x= if(equal(int(s),3),.6,x);
y= if(equal(int(s),3),.2+((ba+tr)*.5)*(1-gam),y);

x= if(equal(int(s),4),.5+sin(ba*100)*.03,x);
y= if(equal(int(s),4),.4,y);

//Corpo
x= if(equal(int(s),5),.5,x);
y= if(equal(int(s),5),.6,y);

//Braccia
x= if(equal(int(s),6),.4-mi*.23,x);
y= if(equal(int(s),6),.5+mi,y);

x= if(equal(int(s),7),.5,x);
y= if(equal(int(s),7),.6,y);

x= if(equal(int(s),8),.6+tr*.23,x);
y= if(equal(int(s),8),.5+tr,y);

x= if(equal(int(s),9),.5,x);
y= if(equal(int(s),9),.6,y);

//Testa
x= if(equal(int(s),10),.5,x);
y= if(equal(int(s),10),.62,y);

x= if(equal(int(s),11),.47-ba*.23,x);
y= if(equal(int(s),11),.62,y);
x= if(equal(int(s),12),.47-ba*.23,x);
y= if(equal(int(s),12),.67+ba*.23,y);

x= if(equal(int(s),13),.53+ba*.23,x);
y= if(equal(int(s),13),.67+ba*.23,y);

x= if(equal(int(s),14),.53+ba*.23,x);
y= if(equal(int(s),14),.62,y);

x= if(equal(int(s),15),.50,x);
y= if(equal(int(s),15),.62,y);

x=x*dim+xpos;
y=y*dim+ypos;

mi_prg= if(above(mi_prg,5),0,mi_prg+mi*.1);
ba_prg= if(above(ba_prg,5),0,ba_prg+ba*.1);
tr_prg= if(above(tr_prg,5),0,tr_prg+tr*.1);

hm=sample+mi2_prg;
ht=sample+tr_prg;
hb=sample+ba_prg;

r=hm;
g=ht;
b=hb;
a=.8;
